/** JLPT level definitions: { jlpt, label, firstGroup, groupCount } */
export const JLPT_LEVELS = [
  { jlpt: 5, label: 'N5', firstGroup: 0, groupCount: 16 },
  { jlpt: 4, label: 'N4', firstGroup: 16, groupCount: 34 },
  { jlpt: 3, label: 'N3', firstGroup: 50, groupCount: 74 },
  { jlpt: 2, label: 'N2', firstGroup: 124, groupCount: 74 },
  { jlpt: 1, label: 'N1', firstGroup: 198, groupCount: 247 },
];

/** Get the JLPT level info for a given group index */
export function jlptForGroup(group) {
  return JLPT_LEVELS.find((l) => group >= l.firstGroup && group < l.firstGroup + l.groupCount);
}
